/**
 * @param {string} s
 * @return {number}
 */
const countBinarySubstrings = function(s) {
    let count = 0;
    let zeros = 0;
    let ones = 0;
    let arr = [];
    let temp = s[0];

    for (let i = 0; i < s.length; i++) {
        if (s[i] === '0') {
            if (temp !== '0') {
                arr.push(ones);
                ones = 0;
                temp = '0';
            } else {
                ones = 0;
            }
            zeros++;
        } else if (s[i] === '1') {
            if (temp !== '1') {
                arr.push(zeros);
                zeros = 0;
                temp = '1';
            } else {
                zeros = 0;
            }
            ones++;
        }
    }
    arr.push(zeros || ones)

    for (let i = 1; i < arr.length; i++) {
        count += Math.min(arr[i], arr[i - 1]);
    }
    return count;
};

console.log(countBinarySubstrings('00110011'));
console.log(countBinarySubstrings('11001100'));
console.log(countBinarySubstrings('10101'));
console.log(countBinarySubstrings('01'));
console.log(countBinarySubstrings('10'));
console.log(countBinarySubstrings('000111'));
// 5718
console.log(countBinarySubstrings(''));
// 5791
console.log(countBinarySubstrings(''));

console.log(countBinarySubstrings(''));
